   160|/**
   161| * POST /api/ivx/owner-auth/login
   162| * Body: { email, password }
   163| * Returns: { access_token, refresh_token, expires_at, user } on success
   164| *
   165| * Uses the Supabase REST auth endpoint directly with the service role key
   166| * as the apikey header — the GoTrue server accepts the service role key
   167| * for password grant when the anon key is not available.
   168| */
   169|export async function handleIVXOwnerAuthLogin(request: Request): Promise<Response> {
   170|  try {
   171|    if (request.method !== 'POST') {
   172|      return json({ ok: false, error: 'Method not allowed.' }, 405);
   173|    }
   174|
   175|    const body = await request.json().catch(() => ({})) as LoginPayload;
   176|    const email = readTrimmed(body.email).toLowerCase();
   177|    const password = readTrimmed(body.password);
