   179|    if (!isValidEmail(email)) {
   180|      return json({ ok: false, error: 'A valid email is required.' }, 400);
   181|    }
   182|    if (!password || password.length < 8) {
   183|      return json({ ok: false, error: 'Password must be at least 8 characters.' }, 400);
   184|    }
   185|
   186|    const ip = readClientIp(request);
   187|    assertRateLimit(`login:${email}:${ip}`);
   188|
   189|    const supabaseUrl = getSupabaseUrl();
   190|    const serviceKey = getServiceRoleKey();
   191|
   192|    // Call Supabase GoTrue password grant endpoint directly.
   193|    // The service role key is accepted as apikey for the token endpoint.
   194|    const response = await fetch(`${supabaseUrl}/auth/v1/token?grant_type=password`, {
   195|      method: 'POST',
   196|      headers: {
   197|        'apikey': serviceKey,
   198|        'Authorization': `Bearer ${serviceKey}`,
   199|        'Content-Type': 'application/json',
   200|      },
   201|      body: JSON.stringify({ email, password }),
   202|      signal: AbortSignal.timeout(15000),
   203|    });
   204|
   205|    const data = await response.json().catch(() => ({})) as Record<string, unknown>;
   206|
   207|    if (!response.ok) {
   208|      const errorMsg = typeof data.error_description === 'string'
   209|        ? data.error_description
   210|        : typeof data.message === 'string'
   211|          ? data.message
   212|          : typeof data.error === 'string'
   213|            ? data.error
   214|            : `Authentication failed (HTTP ${response.status}).`;
   215|
   216|      const isInvalidCreds = response.status === 400 || response.status === 401;
   217|      return json({
   218|        ok: false,
   219|        error: isInvalidCreds ? 'Invalid email or password.' : errorMsg,
   220|        httpStatus: response.status,
   221|        maskedEmail: maskEmail(email),
   222|        deploymentMarker: DEPLOYMENT_MARKER,
   223|        secretValuesReturned: false,
   224|        timestamp: nowIso(),
   225|      }, isInvalidCreds ? 401 : response.status);
   226|    }
   227|
   228|    // Success — return the session tokens to the client
   229|    const accessToken = typeof data.access_token === 'string' ? data.access_token : null;
   230|    const refreshToken = typeof data.refresh_token === 'string' ? data.refresh_token : null;
   231|    const expiresAt = typeof data.expires_at === 'number' ? data.expires_at : null;
   232|    const expiresInSeconds = typeof data.expires_in === 'number' ? data.expires_in : null;
   233|    const tokenType = typeof data.token_type === 'string' ? data.token_type : 'bearer';
   234|    const user = data.user as Record<string, unknown> | undefined;
   235|
   236|    if (!accessToken) {
   237|      return json({ ok: false, error: 'Supabase did not return an access token.', deploymentMarker: DEPLOYMENT_MARKER, secretValuesReturned: false }, 502);
   238|    }
   239|
   240|    return json({
   241|      ok: true,
   242|      session: {
   243|        accessToken,
   244|        refreshToken,
   245|        expiresAt,
   246|        expiresInSeconds,
   247|        tokenType,
   248|      },
   249|      user: user ? {
   250|        id: typeof user.id === 'string' ? user.id : null,
   251|        email: typeof user.email === 'string' ? user.email : null,
   252|        emailConfirmed: Boolean(user.email_confirmed_at || user.confirmed_at),
   253|        createdAt: typeof user.created_at === 'string' ? user.created_at : null,
   254|        role: (user.app_metadata as Record<string, unknown>)?.role as string ?? null,
   255|        accountType: (user.app_metadata as Record<string, unknown>)?.accountType as string ?? null,
   256|        firstName: (user.user_metadata as Record<string, unknown>)?.firstName as string ?? null,
   257|        lastName: (user.user_metadata as Record<string, unknown>)?.lastName as string ?? null,
   258|      } : null,
   259|      maskedEmail: maskEmail(email),
   260|      authProxyUsed: true,
   261|      deploymentMarker: DEPLOYMENT_MARKER,
   262|      secretValuesReturned: false,
   263|      timestamp: nowIso(),
   264|    });
   265|  } catch (error) {
   266|    const message = error instanceof Error ? error.message : 'Owner auth login failed.';
   267|    const isRateLimit = message.toLowerCase().includes('rate limited');
   268|    return json({
   269|      ok: false,
   270|      error: message,
   271|      deploymentMarker: DEPLOYMENT_MARKER,
   272|      secretValuesReturned: false,
   273|      timestamp: nowIso(),
   274|    }, isRateLimit ? 429 : 500);
   275|  }
